<template><div><section class="page-hero compact lab-page-hero"><div><span class="eyebrow">TEST CATALOG</span><h1>检查项目目录</h1><p>查看平台已配置的检查与检验项目、价格和说明</p></div><div class="stock-overview"><div><span>项目总数</span><strong>{{filtered.length}}</strong></div><div><span>检验项目</span><strong>{{items.filter(x=>x.type==='检验').length}}</strong></div></div></section><section class="content-card"><div class="toolbar"><div class="search"><el-input v-model="keyword" :prefix-icon="Search" placeholder="搜索项目名称或说明" clearable/><el-radio-group v-model="type"><el-radio-button value="">全部</el-radio-button><el-radio-button value="检验">检验</el-radio-button><el-radio-button value="检查">检查</el-radio-button></el-radio-group></div><el-button :icon="Refresh" @click="load">刷新</el-button></div><div v-loading="loading" class="item-grid"><article v-for="item in filtered" :key="item.id"><span class="item-icon" :class="item.type==='检验'?'green':'blue'"><el-icon><component :is="item.type==='检验'?Operation:Monitor"/></el-icon></span><div><div class="item-title"><strong>{{item.name}}</strong><el-tag :type="item.type==='检验'?'success':'primary'" size="small" round>{{item.type}}</el-tag></div><p>{{item.description||'暂无项目说明'}}</p><small>项目编号 ITEM{{String(item.id).padStart(4,'0')}}</small></div><b>¥{{Number(item.price).toFixed(2)}}</b></article><el-empty v-if="!filtered.length&&!loading" description="暂无匹配项目"/></div></section></div></template>
<script setup lang="ts">import{computed,onMounted,ref}from'vue';import{Search,Refresh,Operation,Monitor}from'@element-plus/icons-vue';import{getItems}from'@/api/lab';import type{ExaminationItem}from'@/types';const loading=ref(false),items=ref<ExaminationItem[]>([]),keyword=ref(''),type=ref('');const filtered=computed(()=>items.value.filter(x=>(!type.value||x.type===type.value)&&(!keyword.value||x.name.includes(keyword.value)||x.description?.includes(keyword.value))));const load=async()=>{loading.value=true;try{items.value=(await getItems()).data.data}finally{loading.value=false}};onMounted(load)</script>
